import{_ as i,o as a,c as o,ag as n}from"./chunks/framework.DTiDeF2Q.js";const p=JSON.parse('{"title":"Bí Danh Dig | Dotfiles (VI)","titleTemplate":":title","description":"Lệnh truy vấn DNS rút gọn. Tổng quan cho Dotfiles v0.2.495. Tương thích với macOS, Linux và WSL qua Dotfiles.","frontmatter":{"title":"Bí Danh Dig | Dotfiles","description":"Lệnh truy vấn DNS rút gọn. Tổng quan cho Dotfiles v0.2.495. Tương thích với macOS, Linux và WSL qua Dotfiles.","lang":"vi-VN","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Bí Danh Dig | Dotfiles preview","canonical":"/vi/aliases/dig/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Bí danh Dig","pageType":"docs","schemaType":"WebPage","permalink":"/vi/aliases/dig/"},"headers":[],"relativePath":"vi/aliases/dig/index.md","filePath":"vi/aliases/dig/index.md","lastUpdated":1773010926000}'),d={name:"vi/aliases/dig/index.md"};function t(c,e,l,h,r,s){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="bi-danh-dig" tabindex="-1">Bí Danh Dig <a class="header-anchor" href="#bi-danh-dig" aria-label="Permalink to &quot;Bí Danh Dig&quot;">​</a></h1><p>Lệnh truy vấn DNS rút gọn.</p><p>Trang này giới thiệu một nhóm bí danh và các phím tắt lệnh thường dùng. Đọc trang này trước để hiểu quy ước đặt tên, đầu vào mong đợi và mẫu thực thi an toàn. Sau đó mở phụ lục tham khảo để xem toàn bộ danh sách lệnh và cú pháp chính xác. Các bí danh này giảm việc gõ lặp lại và duy trì hành vi quy trình làm việc nhất quán trên macOS, Linux và WSL.</p><h2 id="khi-nao-su-dung" tabindex="-1">Khi Nào Sử Dụng <a class="header-anchor" href="#khi-nao-su-dung" aria-label="Permalink to &quot;Khi Nào Sử Dụng&quot;">​</a></h2><p>Sử dụng trang này trước công việc shell hàng ngày khi bạn cần mẫu lệnh dự đoán được.</p><h2 id="bao-gom" tabindex="-1">Bao Gồm <a class="header-anchor" href="#bao-gom" aria-label="Permalink to &quot;Bao Gồm&quot;">​</a></h2><ul><li>Bí danh: 10</li><li>Hàm hỗ trợ: 0</li><li>Tệp nguồn: 1</li></ul><h2 id="vi-du-nhanh" tabindex="-1">Ví Dụ Nhanh <a class="header-anchor" href="#vi-du-nhanh" aria-label="Permalink to &quot;Ví Dụ Nhanh&quot;">​</a></h2><ul><li><code>d</code> → <code>dig</code></li><li><code>d4</code> → <code>dig +short -4</code></li><li><code>d6</code> → <code>dig +short -6</code></li><li><code>dga</code> → <code>dig +all ANY</code></li><li><code>dgs</code> → <code>dig +short</code></li><li><code>digg</code> → <code>dig @8.8.8.8 +nocmd any +multiline +noall +answer</code></li><li><code>ip4</code> → <code>dig +short myip.opendns.com @resolver1.opendns.com -4</code></li><li><code>ip6</code> → <code>dig -6 AAAA +short myip.opendns.com. @resolver1.opendns.com.</code></li><li><code>ips</code> → <code>ip4; ip6</code></li><li><code>wip</code> → <code>dig +short myip.opendns.com @resolver1.opendns.com</code></li></ul><h2 id="buoc-tiep-theo" tabindex="-1">Bước Tiếp Theo <a class="header-anchor" href="#buoc-tiep-theo" aria-label="Permalink to &quot;Bước Tiếp Theo&quot;">​</a></h2><p>Mở danh sách đầy đủ:</p>',11)])])}const u=i(d,[["render",t]]);export{p as __pageData,u as default};
